func copySealInfos(sealInfos []*SealWrapper, enabledOnly bool) []*SealWrapper {
	ret := make([]*SealWrapper, 0, len(sealInfos))
	for _, si := range sealInfos {
		if enabledOnly && si.Disabled {
			continue
		}
		ret = append(ret, si)
	}
	return ret
}

